const API_URL = 'http://project-collab-api.local/api'; async function apiRequest(endpoint, method = 'GET', data = null) { const token = localStorage.getItem('token'); const headers = { 'Content-Type': 'application/json' }; if(token) { headers['Authorization'] = 'Bearer ' + token; } const config = { method: method, headers: headers }; if(data) { config.body = JSON.stringify(data); } try { const response = await fetch(API_URL + endpoint, config); const result = await response.json(); return result; } catch(error) { console.error('API Error:', error); return { status: 'error', message: 'Ошибка соединения с сервером' }; } } async function login(email, password) { const result = await apiRequest('/auth/login', 'POST', { email, password }); if(result.status === 'success' && result.data?.token) { localStorage.setItem('token', result.data.token); localStorage.setItem('user', JSON.stringify(result.data)); } return result; } async function register(userData) { return await apiRequest('/auth/register', 'POST', userData); } async function getCurrentUser() { return await apiRequest('/auth/me', 'GET'); } async function getProjects(page = 1, limit = 10, skill = '', search = '', sort = 'newest') { let url = `/projects?page=${page}&limit=${limit}&sort=${sort}`; if(skill) url += `&skill=${encodeURIComponent(skill)}`; if(search) url += `&search=${encodeURIComponent(search)}`; return await apiRequest(url); } async function getProject(id) { return await apiRequest(`/projects/${id}`); } async function createProject(projectData) { return await apiRequest('/projects', 'POST', projectData); } async function updateProject(id, projectData) { return await apiRequest(`/projects/${id}`, 'PUT', projectData); } async function deleteProject(id) { return await apiRequest(`/projects/${id}`, 'DELETE'); } async function getUserProjects() { return await apiRequest('/projects/my', 'GET'); } async function bidOnProject(projectId, budget, letter) { return await apiRequest(`/projects/${projectId}/bid`, 'POST', { budget, letter }); } async function getProjectBids(projectId) { return await apiRequest(`/projects/${projectId}/bids`, 'GET'); } async function acceptBid(bidId) { return await apiRequest(`/bids/${bidId}/accept`, 'POST'); } async function rejectBid(bidId) { return await apiRequest(`/bids/${bidId}/reject`, 'POST'); } async function getUserTasks(filter = 'all') { return await apiRequest(`/tasks?filter=${filter}`, 'GET'); } async function getTask(id) { return await apiRequest(`/tasks/${id}`, 'GET'); } async function updateTaskStatus(taskId, status) { return await apiRequest(`/tasks/${taskId}`, 'PUT', { status }); } async function getAvailableTasks(filters = {}) { let url = '/tasks/available?'; const params = new URLSearchParams(filters); return await apiRequest(url + params.toString(), 'GET'); } async function createTaskBid(taskId, bidData) { return await apiRequest(`/tasks/${taskId}/bids`, 'POST', bidData); } async function getUserBids(filter = 'all') { return await apiRequest(`/bids/my?filter=${filter}`, 'GET'); } async function getProjectBids(projectId) { return await apiRequest(`/projects/${projectId}/bids`, 'GET'); } async function acceptBid(bidId) { return await apiRequest(`/bids/${bidId}/accept`, 'POST'); } async function rejectBid(bidId) { return await apiRequest(`/bids/${bidId}/reject`, 'POST'); } window.api = { login, register, getCurrentUser, getProjects, getProject, createProject, updateProject, deleteProject, getUserProjects, bidOnProject, getProjectBids, acceptBid, rejectBid, getUserTasks, getTask, updateTaskStatus, getAvailableTasks, createTaskBid, getUserBids, getProjectBids, acceptBid, rejectBid };